# Day 14: *args, **kwargs

# Default parameter
def power(base, exp=2):
    return base ** exp
print(f"3² = {power(3)}, 2³ = {power(2,3)}")

# *args — any number of values
def average(*args):
    return sum(args) / len(args) if args else 0
print(f"Avg(10,20,30) = {average(10,20,30)}")

# **kwargs — any keyword arguments
def profile(**kwargs):
    for k, v in kwargs.items():
        print(f"  {k}: {v}")
profile(name="Ruban", role="ML Engineer", city="Chennai")

# Combined
def log_event(event, *tags, level="INFO", **meta):
    print(f"\n[{level}] {event}")
    if tags: print(f"  Tags: {', '.join(tags)}")
    for k, v in meta.items():
        print(f"  {k}: {v}")

log_event("Training", "ml", "prod", level="WARN", model="XGBoost")
